bomData.valueScript:
// Filter function to get all the hardware elements for the Duststrip
let HardwareElements = GlobalFunc.find_HardwareLibraryMapping(part.pa_HardwareId);

// Cycle to add all hardware elements to the BOM
HardwareElements.forEach(info => {
  let elem = this.addbomout_Hardware();
  let DuststripBOMInfo = GlobalFunc.find_HardwareLibrary(info.SupplierArticleNumber!,info.Supplier!);
  let DuststripBOMName = GlobalFunc.find_PartSettings("part_Duststrip");

  elem.bom_Supplier=info.Supplier;
  elem.bom_SupplierArticle=info.SupplierArticleNumber;
  elem.bom_Description1=DuststripBOMInfo.Description;
  elem.bom_Description2=DuststripBOMInfo.Description2;
  elem.bom_Length=DuststripBOMInfo.Length;
  elem.bom_Width=DuststripBOMInfo.Width;
  elem.bom_Thk=DuststripBOMInfo.Thickness;
  elem.bom_Color=DuststripBOMInfo.Color;
  elem.bom_Weight=DuststripBOMInfo.Weight;
  elem.bom_Name=DuststripBOMName.BomPartDescription;
  elem.bom_Type=part._partId;
  elem.bom_PartId=part._id;
  elem.bom_ParentId=parentId;
  elem.bom_Qty=info.BomQty;
})
